import{_ as i,o as t,c as a,ag as o}from"./chunks/framework.DTiDeF2Q.js";const p=JSON.parse('{"title":"Alias Tmux | Dotfiles (IT)","titleTemplate":":title","description":"Alias shell per tmux. Scorciatoie per gestione sessioni, finestre e pannelli del multiplexer terminale.","frontmatter":{"title":"Alias Tmux | Dotfiles","description":"Alias shell per tmux. Scorciatoie per gestione sessioni, finestre e pannelli del multiplexer terminale.","lang":"it-IT","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Alias Tmux preview","canonical":"/it/aliases/tmux/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Alias Tmux","pageType":"docs","schemaType":"WebPage","metaTitle":"Alias Tmux - Dotfiles (IT)","permalink":"/it/aliases/tmux/","sidebar":true,"meta":[{"name":"keywords","content":"alias tmux, multiplexer terminale, gestione sessioni, alias shell, dotfiles, produttivita terminale"},{"name":"twitter:card","content":"summary"},{"name":"twitter:description","content":"Alias shell per tmux. Scorciatoie per gestione sessioni, finestre e pannelli del multiplexer terminale."},{"name":"twitter:title","content":"Alias Tmux - Dotfiles"},{"name":"og:title","content":"Alias Tmux - Dotfiles"},{"name":"og:description","content":"Alias shell per tmux. Scorciatoie per gestione sessioni, finestre e pannelli del multiplexer terminale."},{"name":"og:image:alt","content":"Dotfiles - Simply designed to fit your shell life"},{"name":"og:locale","content":"it_IT"}]},"headers":[],"relativePath":"it/aliases/tmux/index.md","filePath":"it/aliases/tmux/index.md","lastUpdated":1773010926000}'),n={name:"it/aliases/tmux/index.md"};function l(r,e,s,d,c,m){return t(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="alias-tmux" tabindex="-1">Alias Tmux <a class="header-anchor" href="#alias-tmux" aria-label="Permalink to &quot;Alias Tmux&quot;">â€‹</a></h1><p>Scorciatoie per il multiplexer terminale tmux.</p><h2 id="panoramica" tabindex="-1">Panoramica <a class="header-anchor" href="#panoramica" aria-label="Permalink to &quot;Panoramica&quot;">â€‹</a></h2><p>Questi alias sono definiti in <code>tmux.aliases.sh</code> e caricati automaticamente da chezmoi. Forniscono comandi brevi per le operazioni tmux comuni.</p><h2 id="riferimento" tabindex="-1">Riferimento <a class="header-anchor" href="#riferimento" aria-label="Permalink to &quot;Riferimento&quot;">â€‹</a></h2><table tabindex="0"><thead><tr><th>Alias</th><th>Descrizione</th></tr></thead><tbody><tr><td><code>tm</code></td><td>Avvia tmux</td></tr><tr><td><code>tma</code></td><td>Collega all&#39;ultima sessione</td></tr><tr><td><code>tmat</code></td><td>Collega a sessione specifica</td></tr><tr><td><code>tmks</code></td><td>Uccidi tutte le sessioni tranne quella corrente</td></tr><tr><td><code>tmka</code></td><td>Uccidi tutte le sessioni (server)</td></tr><tr><td><code>tml</code></td><td>Elenca tutte le sessioni</td></tr><tr><td><code>tmn</code></td><td>Nuova sessione senza nome</td></tr><tr><td><code>tms</code></td><td>Nuova sessione con nome</td></tr><tr><td><code>tmr</code></td><td>Ricarica configurazione tmux</td></tr><tr><td><code>tmls</code></td><td>Elenca finestre</td></tr><tr><td><code>tmlp</code></td><td>Elenca pannelli</td></tr><tr><td><code>tmi</code></td><td>Mostra informazioni tmux</td></tr></tbody></table><h2 id="configurazione" tabindex="-1">Configurazione <a class="header-anchor" href="#configurazione" aria-label="Permalink to &quot;Configurazione&quot;">â€‹</a></h2><p>La configurazione tmux e organizzata in file modulari:</p><ul><li><strong>default</strong> - Impostazioni principali e plugin</li><li><strong>display</strong> - Impostazioni visive e comportamento</li><li><strong>linux</strong> - Funzionalita specifiche piattaforma</li><li><strong>navigation</strong> - Binding tasti completi</li><li><strong>panes</strong> - Impostazioni pannelli</li><li><strong>theme</strong> - Barra stato e stile visivo</li></ul><h2 id="caratteristiche-principali" tabindex="-1">Caratteristiche principali <a class="header-anchor" href="#caratteristiche-principali" aria-label="Permalink to &quot;Caratteristiche principali&quot;">â€‹</a></h2><ul><li>Combinazione colori moderna con barra stato specifica per OS</li><li>Binding tasti intuitivi con Ctrl+a come prefisso</li><li>Controlli completi gestione finestre e pannelli</li><li>Persistenza sessione con tmux-resurrect e tmux-continuum</li><li>Menu aiuto scorrevole (premi <code>Ctrl+a ?</code>)</li><li>Supporto mouse per navigazione facile</li></ul><h2 id="navigazione" tabindex="-1">Navigazione <a class="header-anchor" href="#navigazione" aria-label="Permalink to &quot;Navigazione&quot;">â€‹</a></h2><p>Premi <code>Ctrl+a ?</code> per vedere tutti i binding disponibili. Le funzionalita principali includono:</p><ul><li><strong>Gestione finestre</strong> - Dividi, crea, naviga e rinomina</li><li><strong>Navigazione pannelli</strong> - Muoviti con h/j/k/l stile vim</li><li><strong>Gestione sessioni</strong> - Crea, rinomina e cambia sessione</li><li><strong>Modalita copia</strong> - Selezione vim, ricerca e clipboard</li></ul>',14)])])}const g=i(n,[["render",l]]);export{p as __pageData,g as default};
